const test = require('tape');

test('Example test', function (t) {
  t.equal(1 + 1, 2, 'One plus one should equal two');
  t.end();
});

test('Deep equality test', function (t) {
  t.deepEqual({a: 1}, {a: 1}, 'Objects should be deeply equal');
  t.end();
});

test('Failing test', function (t) {
  t.fail('This test fails intentionally');
  t.end();
});

test('Planned test', function (t) {
  t.plan(2);
  t.equal(1 + 1, 2);
  t.equal(2 + 2, 4);
});

test.skip('Skipped test', function (t) {
  t.fail('This should not run');
});

test('Async test', function (t) {
  setTimeout(function () {
    t.pass('Async code executed');
    t.end();
  }, 1000);
});
